INSERT INTO public.packages VALUES ('a08b3908-5aaa-4804-aa73-3b02d56bcb01', '7d95ca36-9aae-4472-9b51-728da28999e9', '2-Week Basic', 14, 20, 2850.00, 1890.00, 2530000, NULL, NULL, NULL, NULL, NULL, '["Experience 14 days of English language study combined with Melbourne''s world-class arts and cultural scene for families.", "✓ Host family accommodation in Melbourne''s inner suburbs with daily breakfast and dinner", "✓ 20 General English lessons per week with certified, experienced instructors", "✓ Airport pickup from Melbourne Tullamarine Airport on arrival", "✓ Welcome dinner event connecting new students and their families", "✓ Guided visit to the National Gallery of Victoria and Melbourne Arts Precinct", "✓ One weekend cultural excursion — Dandenong Ranges or Great Ocean Road scenic day trip", "✓ Certificate of completion awarded at end of program", "✗ International airfare and airport taxes not covered", "✗ Travel insurance must be arranged independently before departure", "✗ Personal spending money and optional shopping tours not included", "✗ Lunches and snacks on excursion days at own expense"]', 'active', '2026-03-19 13:22:36.727319', '2026-03-27 01:38:10.178381', 1, 2, NULL, NULL, NULL);
INSERT INTO public.packages VALUES ('f2f6b8da-2746-42aa-9042-c852c9b12ccb', 'fddf8d72-2789-454a-ba54-f4046affecf0', 'Package A', 14, NULL, 5800.00, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '["A sample 14-day English program in Sydney used for system testing and package configuration demonstrations.", "✓ Host family accommodation with standard daily meals included", "✓ 20 General English lessons per week with qualified teachers", "✓ Airport pickup from Sydney International Airport on arrival", "✓ Welcome orientation and campus familiarisation tour on day one", "✓ One supervised weekend excursion to a Sydney attraction", "✓ Edubee student portal access for real-time schedule and messaging", "✓ Program completion certificate issued at end of test package", "✗ International airfare not included in test package", "✗ Travel insurance to be arranged by participant", "✗ Personal spending money not covered", "✗ Optional activity upgrades at additional cost"]', 'active', '2026-03-20 16:08:58.637507', '2026-03-27 07:37:00.958', 1, 1, NULL, NULL, NULL);
INSERT INTO public.packages VALUES ('dd491e10-6c2a-4f1a-a351-2fcb70a4551b', '15251eba-0300-4393-9cea-086e286b4757', '2-Week Business', 14, 15, 4500.00, NULL, 4185000, 675000, 165000.00, NULL, 6100.00, NULL, '["A focused 14-day Business English program in Singapore — ideal for professionals and executives seeking practical communication skills.", "✓ Comfortable student residence accommodation in central Singapore with Wi-Fi", "✓ 20 Business English lessons per week covering presentations, negotiations, and email writing", "✓ Changi Airport arrival transfer included on program start date", "✓ Site visit to a Singapore CBD corporate office for real-world business exposure", "✓ Guest speaker series: two industry professionals sharing career insights", "✓ Networking dinner event with fellow professionals from around the world", "✓ Business English certificate issued upon successful completion", "✗ International airfare and visa fees not included", "✗ Travel insurance must be arranged by participant before travel", "✗ Meals outside accommodation not covered unless stated in itinerary", "✗ Optional Marina Bay Sands or Sentosa leisure activities at own cost"]', 'active', '2026-03-18 03:22:56.545509', '2026-03-27 01:38:21.722713', 2, 1, NULL, NULL, NULL);
INSERT INTO public.packages VALUES ('3d1edf88-af68-402f-a247-238c0f47dc1c', 'ad692b74-66e1-4af6-a1b4-e6ed71b22209', '2-Week Intensive', 14, 20, 3200.00, NULL, 2976000, 480000, 117000.00, NULL, 4350.00, NULL, '["A fast-paced 14-day intensive English program in Bangkok — designed for motivated learners seeking rapid language improvement.", "✓ Student guesthouse accommodation in Bangkok''s Sukhumvit district with Wi-Fi", "✓ 25 intensive English lessons per week — grammar, pronunciation, fluency drills", "✓ Suvarnabhumi Airport pickup included on arrival day", "✓ Weekly one-on-one tutoring session with your assigned language coach", "✓ Bangkok city orientation tour: Grand Palace, Chao Phraya River, weekend market", "✓ English pronunciation lab and speaking confidence workshop included", "✓ Progress assessment with personalised feedback report at program end", "✗ International airfare to Bangkok not included in program fees", "✗ Thailand tourist visa fees and travel insurance at own expense", "✗ Meals outside guesthouse breakfast plan not included", "✗ Optional Koh Samet beach day trip at additional cost"]', 'active', '2026-03-18 03:22:56.545509', '2026-03-27 01:38:41.00972', 1, 2, NULL, NULL, NULL);
INSERT INTO public.packages VALUES ('ab58e341-49bd-45ca-a94b-5fcc6072f498', '7d95ca36-9aae-4472-9b51-728da28999e9', '3-Week Arts Program', 21, 18, 4200.00, NULL, 3906000, 630000, 153000.00, NULL, 5700.00, NULL, '["Explore creativity and language over 21 inspiring days in Melbourne — where arts, design, and English learning beautifully converge.", "✓ Host family accommodation in Melbourne''s artsy inner suburbs with daily meals", "✓ 20 English language lessons per week integrated with arts and design themes", "✓ Melbourne Airport arrival transfer included in program", "✓ Studio workshops: painting, sculpture, printmaking, and digital design", "✓ Guided tour of NGV International and the Australian Centre for Contemporary Art", "✓ Participation in Melbourne Open Studio art walk with local artists", "✓ Personal art portfolio developed over 3 weeks, presented at closing showcase", "✗ International airfare to Melbourne not included in program price", "✗ Travel insurance to be arranged independently before departure", "✗ Art supply upgrades beyond provided materials at own expense", "✗ Optional Healesville Sanctuary wildlife excursion at additional cost"]', 'active', '2026-03-18 03:22:56.545509', '2026-03-27 01:39:00.404092', 1, 2, NULL, NULL, NULL);
INSERT INTO public.packages VALUES ('a0aedf37-77c8-48b5-a7fd-131849cd2bfa', '3084c658-17a1-434d-b3e4-36e0a1f8eb2f', '4-Week Academic', 28, 20, 6200.00, NULL, 5766000, 930000, 226000.00, NULL, 8430.00, NULL, '["Four weeks of deep academic English immersion in charming Dublin — where Irish culture and educational excellence go hand in hand.", "✓ Homestay accommodation with an Irish host family, breakfast and dinner daily", "✓ 30 academic English lessons weekly covering university-level grammar and composition", "✓ Dublin Airport transfer included on confirmed arrival date", "✓ Academic coaching sessions: argumentation, literature analysis, and essay structure", "✓ Literary walking tour of Dublin — James Joyce, Oscar Wilde, and Samuel Beckett sites", "✓ Day trip to the Cliffs of Moher and Galway Bay on the Wild Atlantic Way", "✓ Certificate of academic excellence with detailed performance assessment", "✗ International airfare and Ireland entry visa fees not included", "✗ Travel insurance mandatory — must be arranged by participant before flying", "✗ Pub crawl and nightlife activities outside program scope and not covered", "✗ Optional Giant''s Causeway trip to Northern Ireland at extra cost"]', 'active', '2026-03-18 03:22:56.545509', '2026-03-27 01:39:04.262968', 2, 2, NULL, NULL, NULL);
INSERT INTO public.packages VALUES ('394dc150-f157-4498-b88e-56936d924d34', 'f904fe12-b84a-4bb8-a219-722e021dafbc', '2-Week Basic', 14, 20, 2850.00, 1890.00, 2530000, NULL, NULL, NULL, NULL, NULL, '["A perfect 14-day introduction to English immersion in vibrant Vancouver for families seeking quality winter education abroad.", "✓ Warm and welcoming host family accommodation including breakfast and dinner daily", "✓ 20 structured General English lessons per week led by certified TESOL teachers", "✓ Airport pickup from YVR International Airport on arrival day included", "✓ Welcome orientation session with city map, safety briefing and campus tour", "✓ One fully supervised weekend excursion to Whistler or Capilano Suspension Bridge", "✓ Student activity card providing discounts at local museums, cafés, and attractions", "✓ Weekly written progress report shared with parents or guardians", "✗ International airfare and departure taxes not included", "✗ Travel insurance is not provided — strongly recommended before travel", "✗ Personal spending money, souvenirs and optional meal upgrades not covered", "✗ Optional premium activity upgrades available at additional cost"]', 'active', '2026-03-21 15:51:37.274692', '2026-03-27 01:38:06.268985', 1, 1, 'percentage', 10.00, NULL);
INSERT INTO public.packages VALUES ('eaae19b7-9492-48f8-8279-060986ce5a03', 'f904fe12-b84a-4bb8-a219-722e021dafbc', '2-Week Basic', 14, 20, 2850.00, 1890.00, 2530000, NULL, NULL, NULL, NULL, NULL, '["A 14-day Vancouver Winter English program for families of two adults — combining language learning with snowy mountain adventures.", "✓ Host family accommodation in a Greater Vancouver home with breakfast and dinner", "✓ 20 English lessons per week tailored to intermediate-level adult learners", "✓ Complimentary airport pickup from YVR on scheduled arrival date", "✓ Welcome orientation covering program schedule, rules, and emergency contacts", "✓ Group weekend activity — skiing at Grouse Mountain or whale watching tour", "✓ Public transit SkyTrain day pass for independent exploration", "✓ Access to school student lounge, Wi-Fi, and study resources", "✗ International flights and associated taxes not included in package price", "✗ Travel insurance — families must organise prior to departure", "✗ Ski equipment rental and lift tickets not included in weekend excursion", "✗ Personal meals outside host family plan at own expense"]', 'active', '2026-03-20 02:12:06.10464', '2026-03-27 01:38:17.88187', 2, 2, 'percentage', 10.00, NULL);
INSERT INTO public.packages VALUES ('104d49f9-b525-446c-afb9-f1324bb86582', '2b19e5b5-ca7b-4664-894a-49737db8291e', '2-Week Cultural', 14, 15, NULL, NULL, 3650000, 380000, NULL, NULL, NULL, NULL, '["Discover Japan''s rich traditions over 14 immersive days — language, culture, and unforgettable experiences in the heart of Tokyo.", "✓ Safe and comfortable student dormitory accommodation in Tokyo''s Shinjuku district", "✓ Daily Japanese language lessons covering hiragana, katakana, and conversational phrases", "✓ Airport transfer from Narita or Haneda Airport on arrival day", "✓ Traditional kimono dressing experience with professional photography", "✓ Tokyo city highlights tour: Asakusa, Shibuya Crossing, Harajuku, and Meiji Shrine", "✓ Calligraphy and origami cultural workshop sessions included", "✓ Supervised day trip to Nikko or Kamakura ancient temples", "✗ International airfare and Japan entry visa fees not included", "✗ Travel insurance is the responsibility of each participant", "✗ Personal shopping at Harajuku, Akihabara or Shibuya at own expense", "✗ Meals not listed in the program schedule at own cost"]', 'active', '2026-03-18 01:11:40.33133', '2026-03-27 01:38:25.691307', 1, 1, 'fixed', NULL, 180.00);
INSERT INTO public.packages VALUES ('3bd9feb9-4f00-4d26-9a78-1f139845653a', '2b19e5b5-ca7b-4664-894a-49737db8291e', '2-Week Cultural', 14, 15, NULL, NULL, 3650000, 380000, NULL, NULL, NULL, NULL, '["Immerse your family in Japanese language and culture for 14 unforgettable days in Tokyo — history, tradition, and modernity.", "✓ Student dormitory in Tokyo with shared kitchen facilities and internet access", "✓ Daily Japanese language classes from beginner to elementary level", "✓ Tokyo Airport transfer provided on arrival day", "✓ Hands-on sushi-making and ramen-cooking cultural workshop", "✓ Guided visits to Senso-ji Temple in Asakusa and teamLab digital art museum", "✓ Kimono dressing ceremony with commemorative group photograph", "✓ Weekend excursion to Mount Fuji Fuji-Q Highland area", "✗ International airfare and Japan tourist visa costs not included", "✗ Travel insurance is required and must be purchased independently", "✗ Theme park entry at Fuji-Q Highland at own expense", "✗ Souvenir shopping budget not included in package"]', 'active', '2026-03-21 15:51:37.297426', '2026-03-27 01:38:29.476657', 1, 2, 'fixed', NULL, 180.00);
INSERT INTO public.packages VALUES ('15459c54-4958-415c-b355-ee3e0965a146', 'ab0194f8-57f6-4ced-b6a8-cceef1c750ee', '3-Week Academic', 21, 12, NULL, NULL, 5420000, NULL, NULL, NULL, NULL, 3200.00, '["A rigorous 3-week academic English program in London — combining Cambridge-aligned study with rich British history and culture.", "✓ Host family homestay accommodation in Greater London including breakfast and dinner", "✓ 30 academic English lessons per week — reading, writing, research, and critical thinking", "✓ Heathrow or Gatwick Airport transfer on arrival day", "✓ Preparation and coaching for Cambridge B2 First Certificate examination", "✓ Guided visit to the British Museum, Tower of London, and National Theatre", "✓ West End theatre performance attendance included in program", "✓ Certificate of academic achievement issued at program conclusion", "✗ International airfare and UK student visa costs not included", "✗ Travel insurance must be obtained before departure — mandatory", "✗ Cambridge exam registration fee payable separately if sitting official exam", "✗ Personal spending in Oxford Street, Camden Market at own expense"]', 'active', '2026-03-20 02:12:06.118358', '2026-03-27 01:38:44.786941', 1, 1, 'fixed', NULL, 300.00);
INSERT INTO public.packages VALUES ('00c01f18-2232-4731-9654-196ccd72213e', '2b19e5b5-ca7b-4664-894a-49737db8291e', '4-Week Intensive', 28, 15, 3800.00, NULL, 3534000, 570000, 139000.00, NULL, 5170.00, NULL, '["An intensive 4-week Japanese language program in Tokyo — rapid skill-building with deep cultural immersion and expert instructors.", "✓ Student dormitory in central Tokyo with shared living and study spaces", "✓ 25 intensive Japanese lessons weekly — JLPT N5-N4 preparation focus", "✓ Narita or Haneda Airport transfer on first day of program", "✓ Language lab sessions: kanji writing, listening comprehension, and role-play drills", "✓ Cultural field trips: Tsukiji Fish Market, Akihabara electronics town, Harajuku", "✓ JLPT mock examination with tutor review and improvement plan", "✓ Completion certificate and JLPT readiness report issued at program end", "✗ International airfare to Tokyo not included in program fee", "✗ Japan tourist or student visa to be obtained independently", "✗ Travel insurance not covered — strongly recommended before travel", "✗ Official JLPT exam registration at own expense if sitting the actual test"]', 'active', '2026-03-18 03:22:56.545509', '2026-03-27 01:39:12.166676', 1, 1, 'fixed', NULL, 180.00);
INSERT INTO public.packages VALUES ('50368fe9-8dba-46d3-b244-026acd89838f', 'ad692b74-66e1-4af6-a1b4-e6ed71b22209', 'Copy of 2-Week Intensive', 14, NULL, 3200.00, NULL, 2976000, 480000, 117000.00, NULL, 4350.00, NULL, '["A 14-day intensive English immersion experience in Bangkok — faster-paced learning designed for confident and motivated students.", "✓ Air-conditioned student guesthouse accommodation in central Bangkok", "✓ 25 intensive English lessons per week with focus on speaking and pronunciation", "✓ Suvarnabhumi Airport pickup included on day one", "✓ Daily English conversation partner sessions in the evening", "✓ Bangkok cultural highlights: Temple of the Emerald Buddha, Asiatique night market", "✓ Weekend boat trip on the Chao Phraya River with floating market visit", "✓ Certificate of completion with individual language progress summary", "✗ International airfare and Thailand visa not included", "✗ Travel insurance is not provided — arrange prior to departure", "✗ Lunch and dinner outside guesthouse at own expense", "✗ Optional elephant sanctuary or Hua Hin beach trip at extra cost"]', 'active', '2026-03-25 03:40:26.348114', '2026-03-27 01:39:31.44568', 1, 2, NULL, NULL, NULL);
INSERT INTO public.packages VALUES ('60f4085e-0399-49e8-994b-e3769b40a350', '2b19e5b5-ca7b-4664-894a-49737db8291e', '2-Week Cultural', 14, 15, NULL, NULL, 3650000, 380000, NULL, NULL, NULL, NULL, '["A family cultural journey through Tokyo — 14 days of Japanese language learning paired with world-class cultural immersion.", "✓ Dormitory accommodation in central Tokyo with 24/7 resident assistant support", "✓ Japanese language classes covering speaking, listening, and basic reading", "✓ Arrival airport transfer from Narita or Haneda International Airport", "✓ Tea ceremony experience guided by a certified Japanese tea master", "✓ Full-day Tokyo cultural excursion: Ueno Museum, Yanaka district, and Akihabara", "✓ Traditional taiko drumming workshop and performance session", "✓ Farewell dinner with cultural performances and certificate presentation", "✗ International flights to Tokyo not included in this package", "✗ Travel insurance is not provided and must be arranged by families", "✗ Optional anime and manga tours available at additional cost", "✗ Personal spending money for markets, food stalls not covered"]', 'active', '2026-03-20 02:12:06.11519', '2026-03-27 01:38:33.355034', 2, 1, 'fixed', NULL, 180.00);
