INSERT INTO public.chat_documents VALUES ('79b245fa-3ca7-421b-80fd-dc34ac57685e', 'Edubee Camp FAQ', 'test-faq.txt', 'file', 'Edubee Camp FAQ\n\nQ: 캠프 기간은?\nA: 여름 방학 프로그램은 2주에서 4주 과정입니다.\n\nQ: 숙소는?\nA: 호주 현지 홈스테이 또는 기숙사 중 선택 가능합니다.', '2026-03-20 14:30:12.806085', '2026-03-31 21:18:56.969', 'public');
INSERT INTO public.chat_documents VALUES ('6766cca5-f307-4416-805c-9b628ff81b6a', 'Edubee Camp 신청 자격 및 프로그램', NULL, 'manual', 'Edubee Camp 신청 자격은 만 8세에서 18세 학생입니다. 영어 캠프, 문화 체험 프로그램, 여름 방학 프로그램 등 다양한 과정을 제공합니다. 가격은 AUD(호주 달러) 기준으로 표시됩니다. 장학금 제도도 운영 중입니다. 문의는 support@edubee.com으로 해주세요.', '2026-03-20 14:15:43.256341', '2026-03-20 14:15:43.256341', 'internal');
