INSERT INTO public.notes VALUES ('6c08f438-6b18-4b7e-bd66-e6d5f882796c', 'lead', '0daf1a64-ab2d-450f-9d81-14300d64afa3', 'internal', 'Korean student, very interested in 8-week Sydney program. Schedule a follow-up call next week. Passport copy received.', 'internal', false, '9a033493-6fd1-43e4-8f43-c13e3da896cb', '2026-03-19 01:51:54.545846', '2026-03-19 01:51:54.545846');
INSERT INTO public.notes VALUES ('d0230bd8-db2c-4265-8c6d-64b748df6e73', 'application', '7e06b606-5a71-423f-9c89-59b6eefd95a6', 'internal', 'All application documents submitted. Awaiting visa support letter from partner agency. Please confirm ETA by end of week.', 'partner', false, '9a033493-6fd1-43e4-8f43-c13e3da896cb', '2026-03-19 01:51:54.606801', '2026-03-19 01:51:54.606801');
INSERT INTO public.notes VALUES ('a052177e-284f-42ca-bed7-622310c973d3', 'contract', '26798559-9c3f-4690-9adb-24b5ad907531', 'internal', 'First payment deposit confirmed. Remaining balance due 2 weeks before program start. Coordinator notified.', 'internal', false, '9a033493-6fd1-43e4-8f43-c13e3da896cb', '2026-03-19 01:51:54.665108', '2026-03-19 01:51:54.665108');
INSERT INTO public.notes VALUES ('ae5c52fe-b185-4a66-816d-b77ea32e34a9', 'institute_mgt', 'ff3188cb-577a-4140-a32e-bb341316c1a2', 'teacher', 'Sydney campus facility inspection completed. Classroom 3 air conditioning to be replaced before semester start. Students will be notified in advance.', 'client', false, '9a033493-6fd1-43e4-8f43-c13e3da896cb', '2026-03-19 01:51:54.726223', '2026-03-19 01:51:54.726223');
INSERT INTO public.notes VALUES ('e74860ba-2263-4603-b023-a00098fe4c5f', 'hotel_mgt', '472ca27c-5e73-441c-90c5-f25cd361cf31', 'guest', 'Guest requested breakfast add-on for check-in day. Shared with partner hotel for preparation. Confirmed 3 guests total.', 'partner', false, '9a033493-6fd1-43e4-8f43-c13e3da896cb', '2026-03-19 01:51:54.787919', '2026-03-19 01:51:54.787919');
INSERT INTO public.notes VALUES ('5c248c00-f071-4c4d-a431-9149a483ecb8', 'pickup_mgt', 'd8db865b-0be6-440b-aca8-69b1de94477a', 'driver', 'Pickup time changed to 06:30 AM. Driver notified via WhatsApp. 3 passengers confirmed. Terminal 2 International Arrivals.', 'internal', false, '9a033493-6fd1-43e4-8f43-c13e3da896cb', '2026-03-19 01:51:54.845362', '2026-03-19 01:51:54.845362');
INSERT INTO public.notes VALUES ('f6b05a28-14cd-4bd4-879d-56ef4b638b59', 'tour_mgt', 'c01d3415-9fc4-44fe-8c45-806852d663d6', 'guide', 'Bondi Beach tour confirmed. Meet at Opera House forecourt at 9AM. Wear comfortable shoes and bring sunscreen. Lunch included.', 'client', false, '9a033493-6fd1-43e4-8f43-c13e3da896cb', '2026-03-19 01:51:54.90127', '2026-03-19 01:51:54.90127');
INSERT INTO public.notes VALUES ('239584df-4b5c-486c-bcd0-6f98afa42f6c', 'settlement_mgt', 'c6aa4cef-b4ab-48f7-a163-b230255f3476', 'internal', 'Settlement review complete. Final payout after commission deduction: AUD 4,850. Processing scheduled for this Friday.', 'internal', false, '9a033493-6fd1-43e4-8f43-c13e3da896cb', '2026-03-19 01:51:54.959711', '2026-03-19 01:51:54.959711');
INSERT INTO public.notes VALUES ('43a03d55-02bb-4155-a45b-9143a207f47d', 'interview_schedule', 'b53f9d30-ac96-4bd5-a3ec-102bc2cc4018', 'interviewer', 'Interview result: English level confirmed B2+. Clear motivation and positive attitude throughout. Strongly recommended for admission.', 'partner', false, '9a033493-6fd1-43e4-8f43-c13e3da896cb', '2026-03-19 01:51:55.023252', '2026-03-19 01:51:55.023252');
